import { getServerSession } from "next-auth";
import { authOptions } from "../lib/auth";
import { redirect } from "next/navigation";
import { prisma } from "../lib/prisma";
import SymptomsPieChart from "../components/SymptomsPieChart";
import HealthMonitor from "../components/HealthMonitor";

export default async function DashboardPage() {
  const session = await getServerSession(authOptions);
  
  // ตรวจสอบความถูกต้องของเซสชันก่อนดึงข้อมูล
  if (!session || !session.user?.email) {
    redirect("/login");
  }

  // กำหนดช่วงเวลาของเดือนปัจจุบัน
  const now = new Date();
  const firstDayOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
  const lastDayOfMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0);

  // ดึงข้อมูลบันทึกสุขภาพจาก Prisma
  const records = await prisma.healthRecord.findMany({
    where: {
      author: { email: session.user.email },
      date: {
        gte: firstDayOfMonth,
        lte: lastDayOfMonth,
      },
    },
    orderBy: { date: 'desc' },
  });

  // --- Logic การประมวลผลข้อมูลระดับ Enterprise ---
  const totalRecords = records.length;
  
  // สรุปจำนวนอาการแต่ละประเภทสำหรับ Pie Chart
  const symptomData = [
    { label: "ปวดคอ/บ่า", count: records.filter(r => r.neckPain).length },
    { label: "ปวดหลัง", count: records.filter(r => r.backPain).length },
    { label: "ปวดตา", count: records.filter(r => r.eyeStrain).length },
    { label: "ปวดข้อมือ", count: records.filter(r => r.wristPain).length },
    { label: "ปวดหัว", count: records.filter(r => r.headache).length },
    { label: "ชาปลายนิ้ว", count: records.filter(r => r.fingerNumbness).length },
    { label: "ชาที่ขา", count: records.filter(r => r.legNumbness).length },
  ];

  // คำนวณค่าเฉลี่ยและสัดส่วนสำหรับ HealthMonitor
  const stressAvg = totalRecords > 0 
    ? (records.reduce((acc, curr) => acc + curr.stressLevel, 0) / totalRecords).toFixed(1) 
    : "0.0";
  
  const stretchCount = records.filter(r => r.tookBreaks).length;
  const breakRatio = totalRecords > 0 ? stretchCount / totalRecords : 0;

  // ตรวจสอบอาการชาในบันทึกล่าสุด (7 วันล่าสุด)
  const recentRecords = records.slice(0, 7);
  const hasNumbness = recentRecords.some(r => r.fingerNumbness || r.legNumbness);

  // คำนวณหาอาการที่พบบ่อยที่สุด (Top Symptom)
  const sortedSymptoms = [...symptomData].sort((a, b) => b.count - a.count);
  const topSymptom = sortedSymptoms[0];
  const hasSymptoms = topSymptom.count > 0;

  // คำนวณหาจำนวนอาการเฉลี่ยต่อวัน
  const totalSymptomTicks = symptomData.reduce((acc, curr) => acc + curr.count, 0);
  const avgSymptomsPerDay = totalRecords > 0 ? Math.ceil(totalSymptomTicks / totalRecords) : 0;

  return (
    <main style={containerStyle}>
      {/* ส่วนหัวของ Dashboard */}
      <header style={headerStyle}>
        <div>
          <h1 style={titleStyle}>แผงควบคุมสุขภาพ (Dashboard)</h1>
          <p style={subtitleStyle}>
            ผู้ใช้งาน: <span style={{ fontWeight: '700', color: '#0ea5e9' }}>{session.user.name || session.user.email}</span>
          </p>
        </div>
        <div style={monthPickerStyle}>
          <span style={{ fontSize: '14px', fontWeight: '600', color: '#64748b' }}>รอบเดือน: กุมภาพันธ์ 2026</span>
        </div>
      </header>

      {/* Grid Layout สำหรับแสดงผลข้อมูลวิเคราะห์ */}
      <div style={dashboardGrid}>
        
        {/* คอลัมน์ซ้าย: การประเมินความเสี่ยงและแนะนำท่าบริหาร */}
        <section style={monitorSection}>
          <HealthMonitor 
            symptomsCount={avgSymptomsPerDay}
            hasNumbness={hasNumbness}
            breakRatio={breakRatio}
            topSymptom={hasSymptoms ? topSymptom.label : "ความล้าสะสม"}
          />
          
          {/* Key Metrics Cards */}
          <div style={metricsGrid}>
            <article style={{ ...metricCard, borderLeft: '4px solid #ef4444' }}>
              <h3 style={metricLabel}>อาการสูงสุด</h3>
              <p style={metricValue}>{hasSymptoms ? topSymptom.label : "ไม่มี"}</p>
              <span style={metricSub}>สะสม {hasSymptoms ? topSymptom.count : 0} วัน</span>
            </article>

            <article style={{ ...metricCard, borderLeft: '4px solid #f59e0b' }}>
              <h3 style={metricLabel}>ความเหนื่อยล้า</h3>
              <p style={metricValue}>{stressAvg} <span style={{ fontSize: '14px' }}>/ 5</span></p>
              <span style={metricSub}>{Number(stressAvg) > 3 ? "ควรพักผ่อน" : "ปกติ"}</span>
            </article>
          </div>
        </section>

        {/* คอลัมน์ขวา: กราฟวงกลมวิเคราะห์อาการ */}
        <section style={chartSection}>
          <div style={chartCardStyle}>
            <div style={chartHeaderStyle}>
              <h3 style={chartTitleStyle}>สัดส่วนการกระจายตัวของอาการ</h3>
              <p style={chartSubStyle}>Monthly Symptom Distribution</p>
            </div>
            <SymptomsPieChart data={symptomData} />
          </div>
        </section>

      </div>
    </main>
  );
}

// --- Enterprise CSS-in-JS Styles ---
const containerStyle = { maxWidth: '1200px', margin: '0 auto', padding: '60px 24px' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: '40px' };
const titleStyle = { fontSize: '28px', fontWeight: '800', color: '#0f172a', margin: 0 };
const subtitleStyle = { fontSize: '16px', color: '#64748b', marginTop: '4px' };
const monthPickerStyle = { background: '#f8fafc', padding: '10px 20px', borderRadius: '12px', border: '1px solid #e2e8f0' };
const dashboardGrid = { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(450px, 1fr))', gap: '32px' };
const monitorSection = { display: 'flex', flexDirection: 'column' as const, gap: '24px' };
const metricsGrid = { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' };
const metricCard = { background: '#fff', padding: '20px', borderRadius: '16px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)', border: '1px solid #f1f5f9' };
const metricLabel = { margin: 0, fontSize: '13px', color: '#64748b', textTransform: 'uppercase' as const, letterSpacing: '0.5px' };
const metricValue = { margin: '10px 0', fontSize: '22px', fontWeight: '800', color: '#1e293b' };
const metricSub = { fontSize: '12px', fontWeight: '600', color: '#94a3b8' };
const chartSection = { width: '100%' };
const chartCardStyle = { background: '#fff', padding: '32px', borderRadius: '24px', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)', border: '1px solid #e2e8f0' };
const chartHeaderStyle = { marginBottom: '30px', borderBottom: '1px solid #f1f5f9', paddingBottom: '15px' };
const chartTitleStyle = { margin: 0, fontSize: '18px', fontWeight: '800', color: '#0f172a' };
const chartSubStyle = { margin: '4px 0 0 0', fontSize: '14px', color: '#64748b' };